#!/usr/bin/env node
// Generated by Meshly Build Station — redirects the Claude Code harness
// work-tracking tools (TaskCreate / TaskUpdate) to the Meshly Build MCP
// equivalents so all task state lives in one place. Background-process
// helpers (TaskGet/List/Output/Stop) are deliberately not matched by the
// PreToolUse matcher and never reach this script. Do not edit by hand —
// overwritten on the next Station resync.
//
// Escape hatch: `TaskUpdate { status: "deleted" }` is the documented way
// to clear stale local todos out of the harness's session-scoped list,
// and there is no Meshly Build MCP equivalent for that bookkeeping. We
// allow it through. Every other TaskUpdate variant (and every TaskCreate)
// is denied so subagents stop tracking actual work in the wrong place.

const DENY = JSON.stringify({
  hookSpecificOutput: {
    hookEventName: "PreToolUse",
    permissionDecision: "deny",
    permissionDecisionReason:
      "Task tracking for this project lives in Meshly Build — please use " +
      "mcp__meshly-build__create_task / start_task / complete_task / " +
      "get_my_tasks instead.",
  },
});

const ALLOW = JSON.stringify({
  hookSpecificOutput: {
    hookEventName: "PreToolUse",
    permissionDecision: "allow",
  },
});

async function readStdin() {
  let buf = "";
  for await (const chunk of process.stdin) buf += chunk;
  return buf;
}

try {
  const raw = await readStdin();
  const input = raw ? JSON.parse(raw) : null;
  if (
    input &&
    input.tool_name === "TaskUpdate" &&
    input.tool_input &&
    input.tool_input.status === "deleted"
  ) {
    process.stdout.write(ALLOW);
  } else {
    process.stdout.write(DENY);
  }
} catch {
  // Malformed / empty stdin — never silently allow. Deny so a future node
  // runtime change can't quietly bypass the whole guard.
  process.stdout.write(DENY);
}
